---

### Java Code:

```java
import javax.imageio.ImageIO;
import java.awt.image.BufferedImage;
import java.io.*;
import java.net.URL;

public class ImageFilterExample {

    public static void main(String[] args) {
        String imageUrl = "https://example.com/image.jpg"; // Replace with your image URL
        String outputFilePath = "filtered_image.jpg";

        try {
            // Step 1: Download the image
            BufferedImage image = downloadImageFromUrl(imageUrl);
            if (image == null) {
                System.out.println("Failed to download image.");
                return;
            }

            // Step 2: Apply grayscale filter
            BufferedImage filteredImage = applyGrayscaleFilter(image);

            // Step 3: Save the filtered image
            saveImageToFile(filteredImage, outputFilePath);

            System.out.println("Image filtered and saved successfully at: " + outputFilePath);

        } catch (Exception e) {
            System.err.println("An error occurred: " + e.getMessage());
        }
    }

    private static BufferedImage downloadImageFromUrl(String imageUrl) throws IOException {
        BufferedImage image = null;
        try (InputStream inputStream = new URL(imageUrl).openStream()) {
            image = ImageIO.read(inputStream);
        }
        return image;
    }

    private static BufferedImage applyGrayscaleFilter(BufferedImage image) {
        BufferedImage filteredImage = image.copyAsBufferedImage(new BufferedImage(image.getWidth(), image.getHeight(), BufferedImage.TYPE_INT_RGB));

        for (int x = 0; x < image.getWidth(); x++) {
            for (int y = 0; y < image.getHeight(); y++) {
                int rgb = image.getRGB(x, y);
                int r = (rgb >> 16) & 0xFF;
                int g = (rgb >> 8) & 0xFF;
                int b = rgb & 0xFF;

                int gray = (r + g + b) / 3;
                filteredImage.setRGB(x, y, (gray << 16) | (gray << 8) | gray);
            }
        }

        return filteredImage;
    }

    private static void saveImageToFile(BufferedImage image, String outputPath) throws IOException {
        ImageIO.write(image, "jpg", new File(outputPath));
    }
}
```

---

### Notes:
- The `applyGrayscaleFilter` method uses a simple average of the RGB values to convert the image to grayscale.
- You can enhance the filter by using more advanced libraries like **JavaFX** or **OpenCV** for better effects.
- Replace the `imageUrl` with the actual URL of the image you want to process.

