function binarySearch(arr, target) {
    let left = 0;
    let right = arr.length - 1;

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);

        if (arr[mid] === target) {
            return mid; // Target found at index mid
        } else if (arr[mid] < target) {
            left = mid + 1; // Search the right half
        } else {
            right = mid - 1; // Search the left half
        }
    }

    return -1; // Target not found
}

// Example usage:
const sortedArray = [1, 3, 5, 7, 9];
const targetValue = 5;

const index = binarySearch(sortedArray, targetValue);
if (index !== -1) {
    console.log(`Value ${targetValue} found at index ${index}`);
} else {
    console.log(`Value ${targetValue} not found in the array`);
}
```

### Explanation:
- The `binarySearch` function takes an array and a target value as input.
- It initializes `left` and `right` to the start and end of the array, respectively.
- It repeatedly calculates the middle index (`mid`) and compares the value at `mid` with the target.
- If the value matches the target, it returns the index.
- If the value is less than the target, it adjusts the `left` to search the right half.
- If the value is greater, it adjusts the `right` to search the left half.
- If the loop ends without finding the target, it returns `-1`.

### Notes:
- The array must be sorted for binary search to work correctly.
- This implementation assumes the array is sorted in ascending order.
